1	#!/usr/bin/env bun
2	// InferenceOpencode.ts — PAI tool for OpenAI inference via local opencode serve
3	// Output contract: single JSON line matching AnvilProgress.ts format
4	// Usage: bun TOOLS/InferenceOpencode.ts --slug <slug> [--prompt <text>] [--model openai/gpt-5.4]
5	
6	import { createWriteStream, type WriteStream } from "node:fs"
7	import { mkdir, readFile, writeFile } from "node:fs/promises"
8	import { join } from "node:path"
9	import process from "node:process"
10	
11	type Args = { slug: string; prompt?: string; model: string; timeoutMs: number; pulseUrl: string; serverUrl: string; workdir: string }
12	type JsonRecord = Record<string, unknown>
13	type Paths = { eventsFile: string; finalFile: string }
14	type RunState = { timedOut: boolean; interrupted: boolean }
15	type TimeoutControl = { clear: () => void }
16	type SignalControl = { clear: () => void }
17	type RunResult = { verdict: "success"; accumulated: string } | { verdict: "error" | "timeout"; accumulated: string; reason: string }
18	type FinalInput = { verdict: "success" | "error" | "timeout"; exitCode: number | null; eventsFile: string; finalFile: string; durationMs: number; finalMessage: string; reason?: string }
19	
20	const PULSE_TIMEOUT_MS = 2000
21	const POLL_INTERVAL_MS = 600
22	
23	interface OcMessage {
24	  info: {
25	    id: string
26	    role: "user" | "assistant"
27	    finish?: string
28	    tokens?: { input: number; output: number; total: number }
29	    time: { created: number; completed?: number }
30	  }
31	  parts: Array<{ type: string; text?: string }>
32	}
33	
34	function parseArgs(argv: string[]): Args {
35	  const args: Partial<Args> = {
36	    model: "openai/gpt-5.4",
37	    timeoutMs: 120000,
38	    pulseUrl: "http://localhost:31337/notify",
39	    serverUrl: process.env.OPENCODE_SERVER ?? "http://localhost:7878",
40	    workdir: process.env.HOME ?? "/home/jellypai",
41	  }
42	  const seen = new Set<string>()
43	  const valueFor = (flag: string, inline: string | undefined, i: number): [string, number] => {
44	    if (inline !== undefined) return [inline, i]
45	    const v = argv[i + 1]
46	    if (v === undefined || v.startsWith("--")) throw new Error(`${flag} requires a value`)
47	    return [v, i + 1]
48	  }
49	  for (let i = 0; i < argv.length; i += 1) {
50	    const token = argv[i]
51	    if (!token.startsWith("--")) throw new Error(`unexpected positional argument: ${token}`)
52	    const eq = token.indexOf("="), flag = eq === -1 ? token : token.slice(0, eq), inline = eq === -1 ? undefined : token.slice(eq + 1)
53	    if (seen.has(flag)) throw new Error(`duplicate flag: ${flag}`)
54	    seen.add(flag)
55	    const [value, next] = valueFor(flag, inline, i); i = next
56	    switch (flag) {
57	      case "--slug": args.slug = nonEmpty(flag, value); break
58	      case "--prompt": args.prompt = nonEmpty(flag, value); break
59	      case "--model": args.model = nonEmpty(flag, value); break
60	      case "--timeout-ms": args.timeoutMs = positiveInt(flag, value); break
61	      case "--pulse-url": args.pulseUrl = validUrl(flag, value); break
62	      case "--server-url": args.serverUrl = validUrl(flag, value); break
63	      case "--workdir": args.workdir = nonEmpty(flag, value); break
64	      default: throw new Error(`unknown flag: ${flag}`)
65	    }
66	  }
67	  if (!args.slug) throw new Error("--slug is required")
68	  if (!/^[A-Za-z0-9._-]+$/.test(args.slug) || args.slug === "." || args.slug === "..") throw new Error("--slug must be alphanumeric with dots, underscores, or hyphens")
69	  return args as Args
70	}
71	
72	function nonEmpty(flag: string, value: string): string { if (!value.length) throw new Error(`${flag} must not be empty`); return value }
73	function positiveInt(flag: string, value: string): number {
74	  if (!/^\d+$/.test(value)) throw new Error(`${flag} must be a positive integer`)
75	  const n = Number(value)
76	  if (!Number.isSafeInteger(n) || n <= 0) throw new Error(`${flag} must be a positive safe integer`)
77	  return n
78	}
79	function validUrl(flag: string, value: string): string {
80	  try { return new URL(nonEmpty(flag, value)).toString() }
81	  catch (e: unknown) { throw new Error(`${flag} must be a valid URL: ${String(e)}`) }
82	}
83	function errorMessage(error: unknown): string { return error instanceof Error ? error.message : String(error) }
84	function asRecord(v: unknown): JsonRecord | null { return typeof v === "object" && v !== null && !Array.isArray(v) ? v as JsonRecord : null }
85	function homeDir(): string { const home = process.env.HOME; if (!home) throw new Error("HOME is not set"); return home }
86	
87	async function readServerPassword(home: string): Promise<string | null> {
88	  const envVal = process.env.OPENCODE_SERVER_PASSWORD
89	  if (typeof envVal === "string" && envVal.trim().length > 0) return envVal.trim()
90	  try {
91	    const text = await readFile(join(home, ".claude", ".env"), "utf8")
92	    for (const raw of text.split("\n")) {
93	      const line = raw.trimStart()
94	      if (!line.startsWith("OPENCODE_SERVER_PASSWORD=")) continue
95	      const val = line.slice("OPENCODE_SERVER_PASSWORD=".length).replace(/[ \t\r]+$/, "")
96	      if (val.length > 0) return val
97	    }
98	  } catch { /* no .env file — password not set */ }
99	  return null
100	}
101	
102	function authHeaders(password: string | null): Record<string, string> {
103	  if (!password) return {}
104	  // opencode uses HTTP Basic Auth with empty username
105	  return { Authorization: `Basic ${btoa(`:${password}`)}` }
106	}
107	
108	async function ensureSlugDir(home: string, slug: string): Promise<Paths> {
109	  const dir = join(home, ".claude", "PAI", "MEMORY", "WORK", slug)
110	  await mkdir(dir, { recursive: true })
111	  return { eventsFile: join(dir, "opencode-messages.jsonl"), finalFile: join(dir, "opencode-final.txt") }
112	}
113	
114	async function readPrompt(prompt: string | undefined): Promise<string> {
115	  if (prompt !== undefined) return prompt
116	  const stdin = process.stdin as typeof process.stdin & { isTTY?: boolean }
117	  if (stdin.isTTY) return ""
118	  let text = ""
119	  for await (const chunk of stdin) text += typeof chunk === "string" ? chunk : Buffer.from(chunk).toString("utf8")
120	  return text
121	}
122	
123	async function writeLine(stream: WriteStream, line: string): Promise<void> {
124	  if (stream.write(line)) return
125	  await new Promise<void>((resolve, reject) => { stream.once("drain", resolve); stream.once("error", reject) })
126	}
127	async function endStream(stream: WriteStream): Promise<void> {
128	  await new Promise<void>((resolve, reject) => { stream.once("error", reject); stream.end(resolve) })
129	}
130	
131	async function sendNotify(url: string, body: JsonRecord): Promise<void> {
132	  const ctrl = new AbortController(), timer = setTimeout(() => ctrl.abort(), PULSE_TIMEOUT_MS)
133	  try {
134	    const res = await fetch(url, { method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify({ ...body, voice_enabled: false }), signal: ctrl.signal })
135	    if (!res.ok) console.error(`InferenceOpencode: Pulse notify HTTP ${res.status}`)
136	  } catch (e: unknown) { console.error(`InferenceOpencode: Pulse notify failed: ${String(e)}`) }
137	  finally { clearTimeout(timer) }
138	}
139	
140	function wireTimeout(state: RunState, args: Args, onTimeout: () => void): TimeoutControl {
141	  const timer = setTimeout(() => {
142	    state.timedOut = true; onTimeout()
143	    void sendNotify(args.pulseUrl, { message: `InferenceOpencode: timed out after ${args.timeoutMs}ms`, agent: "InferenceOpencode", slug: args.slug })
144	  }, args.timeoutMs)
145	  return { clear: () => clearTimeout(timer) }
146	}
147	
148	function wireSignals(state: RunState, timeoutControl: TimeoutControl, onInterrupt: () => void): SignalControl {
149	  let handled = false
150	  const handler = () => { if (handled) return; handled = true; state.interrupted = true; timeoutControl.clear(); onInterrupt() }
151	  process.once("SIGINT", handler); process.once("SIGTERM", handler)
152	  return { clear: () => { process.off("SIGINT", handler); process.off("SIGTERM", handler) } }
153	}
154	
155	// OpenCode serve HTTP API
156	async function createSession(serverUrl: string, workdir: string, providerID: string, modelID: string, auth: Record<string, string>): Promise<string> {
157	  const res = await fetch(`${serverUrl}/session?directory=${encodeURIComponent(workdir)}`, {
158	    method: "POST",
159	    headers: { "Content-Type": "application/json", ...auth },
160	    body: JSON.stringify({ providerID, modelID, title: "pai-inference", agent: "general" }),
161	  })
162	  if (!res.ok) throw new Error(`Session create failed: HTTP ${res.status}`)
163	  const data = asRecord(await res.json())
164	  if (!data || typeof data.id !== "string") throw new Error("Session create: response missing id")
165	  return data.id
166	}
167	
168	async function sendPromptAsync(serverUrl: string, sessionID: string, workdir: string, text: string, auth: Record<string, string>): Promise<void> {
169	  const res = await fetch(`${serverUrl}/session/${sessionID}/prompt_async?directory=${encodeURIComponent(workdir)}`, {
170	    method: "POST",
171	    headers: { "Content-Type": "application/json", ...auth },
172	    body: JSON.stringify({ parts: [{ type: "text", text }] }),
173	  })
174	  if (res.status !== 204) throw new Error(`Prompt send failed: HTTP ${res.status}`)
175	}
176	
177	async function getMessages(serverUrl: string, sessionID: string, auth: Record<string, string>): Promise<OcMessage[]> {
178	  try {
179	    const res = await fetch(`${serverUrl}/session/${sessionID}/message`, { headers: auth })
180	    if (!res.ok) return []
181	    return (await res.json()) as OcMessage[]
182	  } catch { return [] }
183	}
184	
185	async function tryDeleteSession(serverUrl: string, sessionID: string, auth: Record<string, string>): Promise<void> {
186	  try { await fetch(`${serverUrl}/api/session/${sessionID}`, { method: "DELETE", headers: auth }) } catch { /* best-effort */ }
187	}
188	
189	function extractResponseText(messages: OcMessage[]): string | null {
190	  const assistant = messages.find(m => m.info.role === "assistant" && m.info.finish === "stop")
191	  if (!assistant) return null
192	  const text = assistant.parts.filter(p => p.type === "text" && p.text).map(p => p.text!).join("")
193	  return text || null
194	}
195	
196	async function runInference(args: Args, paths: Paths, prompt: string, auth: Record<string, string>): Promise<RunResult> {
197	  const state: RunState = { timedOut: false, interrupted: false }
198	  let sessionID: string | null = null
199	  let pollResolve: (() => void) | null = null
200	  let accumulated = ""
201	
202	  const wakePoller = () => { if (pollResolve) { const r = pollResolve; pollResolve = null; r() } }
203	  const timeoutControl = wireTimeout(state, args, wakePoller)
204	  const signalControl = wireSignals(state, timeoutControl, wakePoller)
205	  const writer = createWriteStream(paths.eventsFile, { flags: "a" })
206	
207	  try {
208	    const [providerID, modelID] = args.model.includes("/") ? args.model.split("/", 2) : ["openai", args.model]
209	    sessionID = await createSession(args.serverUrl, args.workdir, providerID, modelID, auth)
210	    await sendPromptAsync(args.serverUrl, sessionID, args.workdir, prompt, auth)
211	
212	    const deadline = Date.now() + args.timeoutMs
213	    while (Date.now() < deadline && !state.timedOut && !state.interrupted) {
214	      await new Promise<void>(resolve => {
215	        pollResolve = resolve
216	        setTimeout(() => { if (pollResolve === resolve) { pollResolve = null; resolve() } }, POLL_INTERVAL_MS)
217	      })
218	      if (state.timedOut || state.interrupted) break
219	      const messages = await getMessages(args.serverUrl, sessionID, auth)
220	      await writeLine(writer, `${JSON.stringify({ ts: Date.now(), count: messages.length })}\n`)
221	      const text = extractResponseText(messages)
222	      if (text !== null) { accumulated = text; break }
223	    }
224	
225	    if (state.timedOut) return { verdict: "timeout", accumulated, reason: `timed out after ${args.timeoutMs}ms` }
226	    if (state.interrupted) return { verdict: "error", accumulated, reason: "interrupted" }
227	    if (!accumulated) return { verdict: "error", accumulated, reason: "no response received from opencode serve" }
228	    return { verdict: "success", accumulated }
229	  } catch (error: unknown) {
230	    if (state.timedOut) return { verdict: "timeout", accumulated, reason: `timed out after ${args.timeoutMs}ms` }
231	    if (state.interrupted) return { verdict: "error", accumulated, reason: "interrupted" }
232	    return { verdict: "error", accumulated, reason: errorMessage(error) }
233	  } finally {
234	    timeoutControl.clear(); signalControl.clear()
235	    if (sessionID) await tryDeleteSession(args.serverUrl, sessionID, auth)
236	    await endStream(writer)
237	  }
238	}
239	
240	function formatFinalLine(input: FinalInput): string {
241	  const base: JsonRecord = { verdict: input.verdict, exit_code: input.exitCode, events_file: input.eventsFile, final_file: input.finalFile, duration_ms: input.durationMs, final_message: input.finalMessage }
242	  if (input.reason !== undefined) base.reason = input.reason
243	  return JSON.stringify(base)
244	}
245	function emptyErrorLine(reason: string, startMs: number): string {
246	  return formatFinalLine({ verdict: "error", exitCode: 1, eventsFile: "", finalFile: "", durationMs: Date.now() - startMs, finalMessage: "", reason })
247	}
248	
249	export default async function main(argv: string[]): Promise<number> {
250	  const startMs = Date.now()
251	  let paths: Paths | null = null, finalMessage = ""
252	  try {
253	    const args = parseArgs(argv), home = homeDir()
254	    const password = await readServerPassword(home)
255	    const auth = authHeaders(password)
256	
257	    // Verify server is up before doing anything
258	    try {
259	      const health = await fetch(`${args.serverUrl}/api/health`, { headers: auth })
260	      const data = asRecord(health.ok ? await health.json() : null)
261	      if (!data?.healthy) { process.stdout.write(`{"verdict":"unavailable","reason":"opencode serve not healthy at ${args.serverUrl}"}\n`); return 2 }
262	    } catch (e: unknown) {
263	      process.stdout.write(`{"verdict":"unavailable","reason":"opencode serve unreachable: ${errorMessage(e)}"}\n`); return 2
264	    }
265	
266	    paths = await ensureSlugDir(home, args.slug)
